description:
File: packages/opencode-router/src/pod-manager.ts
Depends on: opencode-1.3.2

Pre-step: add human-id to dependencies in packages/opencode-router/package.json
  "human-id": "^1.0.2"   (MIT, zero deps, adjective-noun-verb format, ~15M combinations)
  Then run: bun install (from packages/opencode-router)

Add import at top of pod-manager.ts:
  import { humanId } from "human-id"

Add export:
  export async function suggestBranch(email: string, repoUrl: string): Promise<string>

Implementation:
  let branch = ""
  for (let i = 0; i < 10; i++) {
    branch = humanId({ separator: "-", capitalize: false })
    const hash = getSessionHash(email, repoUrl, branch)
    try {
      await k8sApi.readNamespacedPersistentVolumeClaim({ name: pvcName(hash), namespace: config.namespace })
      // PVC exists — collision, try next
    } catch (err) {
      if (isNotFound(err)) return branch   // no collision — use this name
      throw err
    }
  }
  return branch  // after 10 attempts just return last (collision astronomically unlikely)
